INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (100, 2.1, "2030/01/01 14:59:59", 1, 130011, 2, 3001, 3001100, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", -416.5, "ヤマト", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (101, 5.68, "2030/01/01 14:59:59", 4, 130011, 2, 3001, 3001101, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", -416.5, "ヤマト", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (102, 0.0, "2030/01/01 14:59:59", 1, 130011, 1, 3001, 3001102, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", -416.5, "ヤマト", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (100, 0.0, "2030/01/01 14:59:59", 1, 130211, 1, 3002, 3002100, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", -416.5, "フブキ", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (101, 0.0, "2030/01/01 14:59:59", 1, 130211, 1, 3002, 3002101, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", -416.5, "フブキ", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (102, 8.53, "2030/01/01 14:59:59", 5, 130211, 2, 3002, 3002102, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", -416.5, "フブキ", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (103, 5.67, "2030/01/01 14:59:59", 7, 130211, 1, 3002, 3002103, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", -416.5, "フブキ", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (104, 0.0, "2030/01/01 14:59:59", 1, 130211, 1, 3002, 3002104, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", -416.5, "フブキ", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (300, 0.0, "2030/01/01 14:59:59", 3, 130211, 3, 3004, 3002300, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", -416.5, "フブキ", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (301, 0.0, "2030/01/01 14:59:59", 7, 130211, 7, 3005, 3002400, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", -416.5, "フブキ", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (200, 4.4, "2030/01/01 14:59:59", 2, 130211, 1, 3003, 3003200, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", -416.5, "フブキ", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (201, 0.0, "2030/01/01 14:59:59", 7, 130211, 7, 3003, 3003201, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", -416.5, "フブキ", "2024/10/31 12:00:00", 0.0);
INSERT INTO `v1_3c4dfe98aa2a6079d807a394ff2ce5fe25d112047433ff7c59b182303f0fb2ac` VALUES (202, 5.6, "2030/01/01 14:59:59", 1, 130211, 2, 3003, 3003202, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", -416.5, "フブキ", "2024/10/31 12:00:00", 0.0);
